import Foundation

// Array creation
var colors = ["Red", "Green", "Blue"]
let numbers = [1, 2, 3, 4, 5]

// Accessing
print("First color: \(colors[0])")
print("Last color: \(colors.last ?? "")")
print("Count: \(colors.count)")

// Modifying
colors.append("Yellow")
colors.insert("Purple", at: 0)
colors.remove(at: 2)
print("Colors: \(colors)")

// Iteration
for (index, color) in colors.enumerated() {
    print("\(index): \(color)")
}

// Array with initial values
let repeated = Array(repeating: "Hi", count: 3)
print("Repeated: \(repeated)")

// Subscript slicing
let slice = numbers[1...3]
print("Slice: \(Array(slice))")
